package com.google.gson.internal.bind;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "com.google.gson.internal.bind.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
    // This class serves as the JUnit runner for Cucumber tests
}

package com.google.gson.internal.bind.steps;

import com.google.gson.internal.bind.JsonTreeReader;
import com.google.gson.stream.JsonToken;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

public class StepDefs {

    private JsonTreeReader reader;
    private Exception exception;

    @Given("I have a JsonTreeReader initialized with an empty JsonObject")
    public void i_have_a_JsonTreeReader_initialized_with_an_empty_JsonObject() {
        String json = "{}";
        this.reader = new JsonTreeReader(com.google.gson.JsonElement.parseString(json));
    }

    @Given("I have a JsonTreeReader initialized with a filled JsonObject containing arrays and nested objects")
    public void i_have_a_JsonTreeReader_initialized_with_a_filled_JsonObject_containing_arrays_and_nested_objects() {
        String json = "{\"array\":[1,2,3],\"nested\":{\"key\":\"value\"},\"string\":\"test\"}";
        this.reader = new JsonTreeReader(com.google.gson.JsonElement.parseString(json));
    }

    @When("I call skipValue")
    public void i_call_skipValue() {
        try {
            this.reader.skipValue();
            this.exception = null;
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("the method should execute without throwing {string}")
    public void the_method_should_execute_without_throwing(String expectedException) {
        if (this.exception != null) {
            assertNotEquals(expectedException, this.exception.getClass().getName());
        }
    }

    @Then("the peek method should return {string}")
    public void the_peek_method_should_return(String expectedToken) throws Exception {
        JsonToken token = this.reader.peek();
        assertEquals(expectedToken, token.toString());
    }
}

